import{_ as e,o as r,c as t,ag as o}from"./chunks/framework.DL-RKwfR.js";const u=JSON.parse('{"title":"👀 认识练练","description":"","frontmatter":{"title":"👀 认识练练","order":1,"lastUpdated":"2026-03-15T04:32:34.563Z"},"headers":[],"relativePath":"-认识练练.md","filePath":"-认识练练.md"}'),i={name:"-认识练练.md"};function l(h,a,n,s,d,p){return r(),t("div",null,[...a[0]||(a[0]=[o('<h1 id="👀-认识练练" tabindex="-1">👀 认识练练 <a class="header-anchor" href="#👀-认识练练" aria-label="Permalink to &quot;👀 认识练练&quot;">​</a></h1><h1 id="练练是什么" tabindex="-1">练练是什么 <a class="header-anchor" href="#练练是什么" aria-label="Permalink to &quot;练练是什么&quot;">​</a></h1><p>AI 驱动的<strong>企业经验萃取</strong>和<strong>训练平台</strong>，与 AI 进行实战对练，获得量化分析和个性化辅导。</p><p>练练是一个 AI 驱动的训练平台，通过萃取企业自身经验，由 AI 模拟真实场景，让 AI 教练带着员工在“实战”中反复练习它们，从而真正掌握企业所需要的技能。</p><h1 id="产品理念" tabindex="-1">产品理念 <a class="header-anchor" href="#产品理念" aria-label="Permalink to &quot;产品理念&quot;">​</a></h1><p>通过观看视频 ，并不能学会骑⾃⾏⻋。</p><p>同样，你也不能通过这种⽅式，让员工学会所需的技能。</p><h1 id="你是否也遇到了这些问题" tabindex="-1">你是否也遇到了这些问题 <a class="header-anchor" href="#你是否也遇到了这些问题" aria-label="Permalink to &quot;你是否也遇到了这些问题&quot;">​</a></h1><ul><li><strong>经过同样的培训，上岗后为何业绩相差十倍？</strong></li><li><strong>内部分享一场接一场，有没有学会完全不知道？</strong></li><li><strong>新产品推出，怎么让大家快速熟悉，能向客户说明白？</strong></li><li><strong>要检查每个人成果并做针对性反馈，根本忙不过来？</strong></li><li><strong>团队销售冠军的秘诀在哪里？</strong></li><li><strong>怎么样拉高团队整体能力水平？</strong></li></ul><h1 id="how-it-works" tabindex="-1">How it works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How it works&quot;">​</a></h1><h2 id="_01-萃取企业经验" tabindex="-1">01 萃取企业经验 <a class="header-anchor" href="#_01-萃取企业经验" aria-label="Permalink to &quot;01 萃取企业经验&quot;">​</a></h2><p>从企业的知识库、培训 PPT、销冠客户录音等资料中，通过萃取 AI 模型快速提炼出如客户异议、应对技巧和话术等企业自己的经验。</p><h2 id="_02-模拟实战场景" tabindex="-1">02 模拟实战场景 <a class="header-anchor" href="#_02-模拟实战场景" aria-label="Permalink to &quot;02 模拟实战场景&quot;">​</a></h2><p>利用萃取的素材和经验，快速生成可以让团队用于练习和考核的实战场景，精准模拟各种真实客户对话的场景。</p><h2 id="_03-量化分析与辅导" tabindex="-1">03 量化分析与辅导 <a class="header-anchor" href="#_03-量化分析与辅导" aria-label="Permalink to &quot;03 量化分析与辅导&quot;">​</a></h2><p>从流利度、异议处理等多维度，来为员工的能力进行客观的评分，并提供详细的分析报告。</p><p>对每个人的每个回答进行辅导，提供专门的“改进建议”和“润色表达”。</p><h1 id="我们做有何不同" tabindex="-1">我们做有何不同 <a class="header-anchor" href="#我们做有何不同" aria-label="Permalink to &quot;我们做有何不同&quot;">​</a></h1><h3 id="🌟-真实" tabindex="-1">🌟 真实 <a class="header-anchor" href="#🌟-真实" aria-label="Permalink to &quot;🌟 真实&quot;">​</a></h3><p>更真客户，练得更真实</p><p>能模拟更真实客户，像是和真实客户在沟通。</p><h3 id="💧-萃取" tabindex="-1">💧 萃取 <a class="header-anchor" href="#💧-萃取" aria-label="Permalink to &quot;💧 萃取&quot;">​</a></h3><p>企业经验萃得出，用得上</p><p>基于得到沉淀多年的萃取方法论，形成 的 AI 萃取模型。</p><h3 id="🔤-量化" tabindex="-1">🔤 量化 <a class="header-anchor" href="#🔤-量化" aria-label="Permalink to &quot;🔤 量化&quot;">​</a></h3><p>沟通过程可分析和量化</p><p>对沟通能力的评价从纯主观判断，变为可客观量化。</p><h3 id="🤖-ai-化" tabindex="-1">🤖 AI 化 <a class="header-anchor" href="#🤖-ai-化" aria-label="Permalink to &quot;🤖 AI 化&quot;">​</a></h3><p>人只做决策，AI 替你干</p><p>管理动作、工作方式等，均可驱动 AI 帮你干，几分钟搞定。</p><h1 id="适合的企业" tabindex="-1">适合的企业 <a class="header-anchor" href="#适合的企业" aria-label="Permalink to &quot;适合的企业&quot;">​</a></h1><ol><li>一把手重视员工的培训，对 AI 实践有探索欲</li><li>企业内部本就有自己的培训机制</li><li>员工有大量沟通场景（对外销售、服务，对内沟通协作等）</li><li>企业的产品迭代更新快，需要与员工快速适应变化</li></ol><h1 id="进化时间线" tabindex="-1">进化时间线 <a class="header-anchor" href="#进化时间线" aria-label="Permalink to &quot;进化时间线&quot;">​</a></h1><h1 id="快速导航链接" tabindex="-1">快速导航链接 <a class="header-anchor" href="#快速导航链接" aria-label="Permalink to &quot;快速导航链接&quot;">​</a></h1><p>🖥️ 我们的官网</p><p>💰[文档链接]</p>',36)])])}const b=e(i,[["render",l]]);export{u as __pageData,b as default};
